# Track active connections
active_connections: set[WebSocket] = set()


@app.websocket("/ws/chat")
async def chat(websocket: WebSocket):
    await websocket.accept()
    active_connections.add(websocket)
    client_id = f"{websocket.client.host}:{websocket.client.port}"
    logger.info(f"Client {client_id} connected. Total: {len(active_connections)}")

    try:
        while True:
            message = await websocket.receive_text()
            # Broadcast to all other clients
            for conn in active_connections:
                if conn != websocket:
                    try:
                        await conn.send_text(f"[{client_id}] {message}")
                    except Exception:
                        # Other client might have disconnected
                        pass

    except WebSocketDisconnect as e:
        # Clean disconnect handling
        active_connections.discard(websocket)
        logger.info(
            f"Client {client_id} disconnected: "
            f"code={e.code}, reason={getattr(e, 'reason', 'N/A')}. "
            f"Remaining: {len(active_connections)}"
        )
        # Notify others
        for conn in active_connections:
            try:
                await conn.send_text(f"[{client_id}] left the chat")
            except Exception:
                pass

    except Exception as e:
        # Unexpected errors (not a disconnect)
        active_connections.discard(websocket)
        logger.error(f"Unexpected error for {client_id}: {e}")
        try:
            await websocket.close(code=1011, reason="Internal error")
        except Exception:
            pass  # Connection might already be closed


