class ChatRoomManager:
    """Manages multiple chat rooms with user tracking."""

    def __init__(self):
        # room_id -> {websocket: username}
        self.rooms: dict[str, dict[WebSocket, str]] = defaultdict(dict)

    async def join(
        self, room_id: str, websocket: WebSocket, username: str,
    ):
        await websocket.accept()
        self.rooms[room_id][websocket] = username
        # Notify everyone in the room
        await self.broadcast(room_id, {
            "type": "system",
            "content": f"{username} joined the room",
            "users": self.get_users(room_id),
        })

    async def leave(self, room_id: str, websocket: WebSocket):
        username = self.rooms[room_id].pop(websocket, "unknown")
        if not self.rooms[room_id]:
            del self.rooms[room_id]  # Clean up empty rooms
        else:
            await self.broadcast(room_id, {
                "type": "system",
                "content": f"{username} left the room",
                "users": self.get_users(room_id),
            })
        return username

    async def broadcast(
        self,
        room_id: str,
        message: dict,
        exclude: WebSocket | None = None,
    ):
        """Send a message to all clients in a room."""
        disconnected = []
        for ws in self.rooms.get(room_id, {}):
            if ws == exclude:
                continue
            try:
                await ws.send_json(message)
            except Exception:
                disconnected.append(ws)
        # Clean up any broken connections found during broadcast
        for ws in disconnected:
            self.rooms[room_id].pop(ws, None)

    def get_users(self, room_id: str) -> list[str]:
        return list(self.rooms.get(room_id, {}).values())

    def get_room_count(self, room_id: str) -> int:
        return len(self.rooms.get(room_id, {}))


