from collections import defaultdict
import time

class WebSocketRateLimiter:
    def __init__(self, max_messages: int, window_seconds: float):
        self.max_messages = max_messages
        self.window = window_seconds
        self.message_counts: dict[str, list[float]] = defaultdict(list)

    def check(self, client_id: str) -> bool:
        now = time.time()
        timestamps = self.message_counts[client_id]
        # Remove old timestamps
        self.message_counts[client_id] = [
            t for t in timestamps if now - t < self.window
        ]
        if len(self.message_counts[client_id]) >= self.max_messages:
            return False
        self.message_counts[client_id].append(now)
        return True

