from fastapi import FastAPI, WebSocket, WebSocketDisconnect
import asyncio
import time
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI()


# --- Application-level heartbeat with concurrent ping task ---
@app.websocket("/ws/heartbeat")
async def heartbeat_endpoint(websocket: WebSocket):
    await websocket.accept()
    last_pong = time.time()
    PING_INTERVAL = 15  # Send ping every 15 seconds
    PONG_TIMEOUT = 30   # Close if no pong for 30 seconds

    async def ping_loop():
        """Periodically sends pings and checks for timeouts."""
        nonlocal last_pong
        while True:
            await asyncio.sleep(PING_INTERVAL)
            try:
                await websocket.send_json({"type": "ping"})
                # Check if we have received a pong recently
                if time.time() - last_pong > PONG_TIMEOUT:
                    logger.warning("Pong timeout -- closing connection")
                    await websocket.close(code=1001, reason="Pong timeout")
                    return
            except Exception:
                return  # Connection already closed

    ping_task = asyncio.create_task(ping_loop())

    try:
        while True:
            data = await websocket.receive_json()
            if data.get("type") == "pong":
                last_pong = time.time()
                logger.debug("Pong received")
            else:
                # Handle normal messages
                await websocket.send_json({
                    "type": "echo",
                    "data": data,
                })
    except WebSocketDisconnect:
        logger.info("Client disconnected")
    finally:
        ping_task.cancel()
        try:
            await ping_task
        except asyncio.CancelledError:
            pass


# --- Timeout-based approach (simpler) ---
@app.websocket("/ws/timeout")
async def timeout_endpoint(websocket: WebSocket):
    """Closes connection if no message received within timeout."""
    await websocket.accept()
    IDLE_TIMEOUT = 60  # Close after 60 seconds of silence

    try:
        while True:
            try:
                data = await asyncio.wait_for(
                    websocket.receive_text(),
                    timeout=IDLE_TIMEOUT,
                )
                await websocket.send_text(f"Echo: {data}")
            except asyncio.TimeoutError:
                logger.info("Idle timeout -- closing connection")
                await websocket.close(
                    code=1001, reason="Idle timeout"
                )
                break
    except WebSocketDisconnect:
