from fastapi import FastAPI, WebSocket, WebSocketDisconnect, Query
from collections import defaultdict, deque
from datetime import datetime, timezone
import json
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI()


# --- Server-side: message buffer for replay on reconnect ---
class MessageBuffer:
    """Stores recent messages per room for reconnection replay."""

    def __init__(self, max_size: int = 100):
        self.buffers: dict[str, deque] = defaultdict(
            lambda: deque(maxlen=max_size)
        )
        self.counter = 0

    def add(self, room: str, message: dict) -> int:
        self.counter += 1
        entry = {"id": self.counter, **message}
        self.buffers[room].append(entry)
        return self.counter

    def get_since(self, room: str, last_id: int) -> list[dict]:
        """Returns all messages after the given ID."""
        return [
            msg for msg in self.buffers[room]
            if msg["id"] > last_id
        ]


buffer = MessageBuffer(max_size=200)
rooms: dict[str, set[WebSocket]] = defaultdict(set)


@app.websocket("/ws/chat/{room_id}")
async def chat_with_replay(
    websocket: WebSocket,
    room_id: str,
    last_event_id: int = Query(default=0),
):
    """WebSocket endpoint that supports message replay on reconnect."""
    await websocket.accept()
    rooms[room_id].add(websocket)

    # Replay missed messages
    if last_event_id > 0:
        missed = buffer.get_since(room_id, last_event_id)
        for msg in missed:
            await websocket.send_json(msg)
        await websocket.send_json({
            "type": "system",
            "content": f"Replayed {len(missed)} missed messages",
        })

    try:
        while True:
            data = await websocket.receive_json()
            message = {
                "type": "chat",
                "content": data.get("content", ""),
                "timestamp": datetime.now(timezone.utc).isoformat(),
            }
            msg_id = buffer.add(room_id, message)
            message["id"] = msg_id

            # Broadcast to all in room
            dead = set()
            for ws in rooms[room_id]:
                try:
                    await ws.send_json(message)
                except Exception:
                    dead.add(ws)
            rooms[room_id] -= dead

    except WebSocketDisconnect:
        rooms[room_id].discard(websocket)
        logger.info(f"Client disconnected from room {room_id}")


