CLIENT_JS = """
class ReconnectingWebSocket {
    constructor(url, options = {}) {
        this.url = url;
        this.maxRetries = options.maxRetries || 10;
        this.retries = 0;
        this.lastEventId = 0;
        this.onmessage = null;
        this.onopen = null;
        this.onclose = null;
        this.connect();
    }

    connect() {
        // Append last_event_id for replay
        const sep = this.url.includes('?') ? '&' : '?';
        const wsUrl = `${this.url}${sep}last_event_id=${this.lastEventId}`;
        this.ws = new WebSocket(wsUrl);

        this.ws.onopen = () => {
            console.log('Connected');
            this.retries = 0;  // Reset on successful connection
            if (this.onopen) this.onopen();
        };

        this.ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            // Track last event ID for reconnection
            if (data.id) this.lastEventId = data.id;
            if (this.onmessage) this.onmessage(data);
        };

        this.ws.onclose = (event) => {
            if (this.retries >= this.maxRetries) {
                console.error('Max retries reached');
                if (this.onclose) this.onclose(event);
                return;
            }
            // Exponential backoff with jitter
            const base = Math.min(1000 * Math.pow(2, this.retries), 30000);
            const jitter = base * 0.5 * Math.random();
            const delay = base + jitter;
            console.log(`Reconnecting in ${Math.round(delay)}ms...`);
            this.retries++;
            setTimeout(() => this.connect(), delay);
        };
    }

    send(data) {
        if (this.ws.readyState === WebSocket.OPEN) {
            this.ws.send(JSON.stringify(data));
        }
    }
}

